package com.chaobo.scm.supplier.infrastructure.persistence.item;import com.chaobo.scm.supplier.application.item.SupplierItemHistoryPort;import com.chaobo.scm.supplier.domain.item.SupplierItemAggregate;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.springframework.stereotype.Repository;
@Repository public class MyBatisSupplierItemHistoryAdapter implements SupplierItemHistoryPort{private final SupplierItemHistoryMapper mapper;private final IdentifierGenerator ids;public MyBatisSupplierItemHistoryAdapter(SupplierItemHistoryMapper mapper,IdentifierGenerator ids){this.mapper=mapper;this.ids=ids;}public void recordCondition(SupplierItemAggregate aggregate,String type,long operator){var condition=aggregate.condition();mapper.insert(ids.nextId(),aggregate.itemId(),aggregate.supplierId(),aggregate.skuCode(),aggregate.supplierSkuCode(),condition.moq(),condition.mpq(),condition.leadTimeDays(),condition.purchaseUnit(),condition.effectiveFrom(),condition.effectiveTo(),aggregate.version(),type,operator);}}
